// Baseado no Prepara os dados2 do COLETA DE DADOS
// ===========================================

const lojaContext = $('Loop Lojas').item.json;
const EMPRESA_ID = lojaContext.empresa_id;
const LOJA_ID = lojaContext.loja_id;
const CODIGO_LOJA = lojaContext.codigo_loja;

const content = $input.first().json.content;

if (!content || !Array.isArray(content)) {
  return [];
}

// Espécies fiscais válidas (apenas NF, IF, FF)
const ESPECIES_FISCAIS = ['NF', 'IF', 'FF'];

const items = [];

for (const doc of content) {
  if (!doc.jaFaturado) continue;

  const itensArray = doc.itens || [];

  for (const item of itensArray) {
    const numeroFaturamento = item.numeroFaturamento?.replace(/^0+/, '');
    const especieFaturamento = item.especieFaturamento;
    const dataFaturamento = item.dataFaturamento;

    // Filtrar apenas documentos fiscais válidos
    if (!numeroFaturamento || !especieFaturamento) continue;
    if (!ESPECIES_FISCAIS.includes(especieFaturamento)) continue;
    if (!dataFaturamento) continue;

    // Calcular margem (igual ao COLETA DE DADOS)
    const precoDigitado = item.precoDigitado || item.precoUnitario || 0;
    const totalCusto = item.totalCusto || 0;
    const quantidade = item.quantidade || 1;
    const custoUnitario = quantidade > 0 ? totalCusto / quantidade : 0;
    const margem = precoDigitado > 0
      ? Number(((precoDigitado - custoUnitario) / precoDigitado * 100).toFixed(2))
      : 0;

    // Extrair unidade de medida (L, KG, ML, G, BD=balde=litros)
    const descricaoCompleta = item.descricaoCompleta || item.descricaoProduto || '';
    let medidaMatch = descricaoCompleta.match(/(\d+(?:[.,]\d+)?)\s*(L|KG|ML|G)\b/i);
    if (!medidaMatch) {
      medidaMatch = descricaoCompleta.match(/(\d+(?:[.,]\d+)?)\s*BD\b/i);
    }

    let unidade_medida = null;
    if (medidaMatch) {
      let valor = parseFloat(medidaMatch[1].replace(',', '.'));
      const unidade = (medidaMatch[2] || 'L').toUpperCase();

      if (unidade === 'ML') {
        valor = valor / 1000;
        unidade_medida = valor + 'L';
      } else if (unidade === 'G' && valor >= 100) {
        valor = valor / 1000;
        unidade_medida = valor + 'KG';
      } else if (unidade === 'BD' || unidade === 'L') {
        unidade_medida = valor + 'L';
      } else {
        unidade_medida = valor + unidade;
      }
    }

    // Calcular desconto
    const precoOriginal = item.precoOriginal || 0;
    const precoUnitario = item.precoUnitario || 0;
    const descontoValor = precoOriginal > precoUnitario
      ? Number((precoOriginal - precoUnitario).toFixed(2))
      : 0;
    const descontoPercentual = precoOriginal > 0 && descontoValor > 0
      ? Number((descontoValor / precoOriginal * 100).toFixed(2))
      : 0;

    items.push({
      json: {
        empresa_id: EMPRESA_ID,
        loja_id: LOJA_ID,
        codigo_loja: CODIGO_LOJA,
        numero_faturamento: numeroFaturamento,
        especie_faturamento: especieFaturamento,
        data_faturamento: dataFaturamento,

        // Vendedor
        codigo_vendedor: doc.codigoVendedor || null,
        nome_vendedor: doc.nomeVendedor || null,

        // Cliente
        codigo_cliente: doc.cliente?.codigoCliente?.replace(/^0+/, '') || null,
        nome_cliente: doc.cliente?.nome || doc.nomeConsumidorOuCliente || null,

        // Produto
        codigo_produto: item.codigoProduto || '',
        descricao_produto: item.descricaoProduto || '',
        codigo_marca: item.codigoMarca || '',
        unidade_medida: unidade_medida,
        quantidade: quantidade,

        // Preços e Margem
        preco_unitario: precoUnitario,
        preco_original: precoOriginal,
        desconto_valor: descontoValor,
        desconto_percentual: descontoPercentual,
        margem_percentual: margem,

        // Valores
        total_item: item.totalItem || 0,
        total_frete: item.totalFrete || 0
      }
    });
  }
}

return items;

